package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer implements the Transformer interface for testing
type mockTransformer struct {
	transformFromStorageResult []byte
	transformFromStorageStale  bool
	transformFromStorageErr    error
	transformToStorageResult   []byte
	transformToStorageErr      error
	fromStorageCalls           int
	toStorageCalls             int
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.fromStorageCalls++
	return m.transformFromStorageResult, m.transformFromStorageStale, m.transformFromStorageErr
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.toStorageCalls++
	return m.transformToStorageResult, m.transformToStorageErr
}

// roundTripTransformer implements a simple encrypt/decrypt round trip
type roundTripTransformer struct {
	prefix []byte
}

func (r *roundTripTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	// Simple transformation: remove the marker byte
	if len(data) == 0 {
		return nil, false, fmt.Errorf("empty data")
	}
	if data[0] != 'E' {
		return nil, false, fmt.Errorf("invalid encryption marker")
	}
	return data[1:], false, nil
}

func (r *roundTripTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	// Simple transformation: add a marker byte
	result := make([]byte, len(data)+1)
	result[0] = 'E'
	copy(result[1:], data)
	return result, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext returns its bytes as authenticated data
func TestDefaultContextAuthenticatedData(t *testing.T) {
	tests := []struct {
		name     string
		input    DefaultContext
		expected []byte
	}{
		{
			name:     "non-empty context",
			input:    DefaultContext([]byte("test-data")),
			expected: []byte("test-data"),
		},
		{
			name:     "empty context",
			input:    DefaultContext([]byte{}),
			expected: []byte{},
		},
		{
			name:     "context with special characters",
			input:    DefaultContext([]byte{0, 1, 2, 255}),
			expected: []byte{0, 1, 2, 255},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := tt.input.AuthenticatedData()
			if !bytes.Equal(result, tt.expected) {
				t.Errorf("expected %v, got %v", tt.expected, result)
			}
		})
	}
}

// TestPrefixTransformerMatch tests that PrefixTransformer correctly matches and strips prefixes
func TestPrefixTransformerMatch(t *testing.T) {
	tests := []struct {
		name            string
		prefix          []byte
		data            []byte
		shouldMatch     bool
		expectedStripped []byte
	}{
		{
			name:            "prefix matches at start",
			prefix:          []byte("enc:"),
			data:            []byte("enc:encrypted-data"),
			shouldMatch:     true,
			expectedStripped: []byte("encrypted-data"),
		},
		{
			name:            "prefix does not match",
			prefix:          []byte("other:"),
			data:            []byte("enc:encrypted-data"),
			shouldMatch:     false,
		},
		{
			name:            "empty prefix always matches",
			prefix:          []byte{},
			data:            []byte("any-data"),
			shouldMatch:     true,
			expectedStripped: []byte("any-data"),
		},
		{
			name:            "prefix is exact match",
			prefix:          []byte("test"),
			data:            []byte("test"),
			shouldMatch:     true,
			expectedStripped: []byte{},
		},
		{
			name:            "data shorter than prefix",
			prefix:          []byte("prefix"),
			data:            []byte("pre"),
			shouldMatch:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			matched := bytes.HasPrefix(tt.data, tt.prefix)
			if matched != tt.shouldMatch {
				t.Errorf("expected match %v, got %v", tt.shouldMatch, matched)
			}
			if matched && !bytes.Equal(tt.data[len(tt.prefix):], tt.expectedStripped) {
				t.Errorf("expected stripped data %v, got %v", tt.expectedStripped, tt.data[len(tt.prefix):])
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt-decrypt round trip
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name     string
		data     []byte
		ctx      context.Context
		dataCtx  Context
	}{
		{
			name:    "simple round trip",
			data:    []byte("secret-data"),
			ctx:     context.Background(),
			dataCtx: DefaultContext([]byte("auth-data")),
		},
		{
			name:    "empty data round trip",
			data:    []byte{},
			ctx:     context.Background(),
			dataCtx: nil,
		},
		{
			name:    "with request context",
			data:    []byte("test-value"),
			ctx:     genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "pods"}),
			dataCtx: DefaultContext([]byte("pod-auth")),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &roundTripTransformer{}

			// Transform to storage
			encrypted, err := transformer.TransformToStorage(tt.ctx, tt.data, tt.dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage
			decrypted, stale, err := transformer.TransformFromStorage(tt.ctx, encrypted, tt.dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round trip
			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("round trip failed: expected %v, got %v", tt.data, decrypted)
			}

			// Verify not marked as stale for first transformer
			if stale {
				t.Errorf("expected stale=false, got stale=true")
			}
		})
	}
}

// TestNewPrefixTransformersValidation tests NewPrefixTransformers with various inputs
func TestNewPrefixTransformersValidation(t *testing.T) {
	tests := []struct {
		name             string
		err              error
		transformers     []PrefixTransformer
		shouldNotBeNil   bool
	}{
		{
			name:           "nil error creates default error",
			err:            nil,
			transformers:   []PrefixTransformer{{Prefix: []byte("enc:"), Transformer: &mockTransformer{}}},
			shouldNotBeNil: true,
		},
		{
			name:           "custom error is used",
			err:            fmt.Errorf("custom error"),
			transformers:   []PrefixTransformer{{Prefix: []byte("enc:"), Transformer: &mockTransformer{}}},
			shouldNotBeNil: true,
		},
		{
			name:           "multiple transformers",
			err:            fmt.Errorf("error"),
			transformers:   []PrefixTransformer{
				{Prefix: []byte("enc1:"), Transformer: &mockTransformer{}},
				{Prefix: []byte("enc2:"), Transformer: &mockTransformer{}},
			},
			shouldNotBeNil: true,
		},
		{
			name:           "empty transformers list",
			err:            fmt.Errorf("error"),
			transformers:   []PrefixTransformer{},
			shouldNotBeNil: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := NewPrefixTransformers(tt.err, tt.transformers...)
			if (result != nil) != tt.shouldNotBeNil {
				t.Errorf("expected NewPrefixTransformers to return non-nil: %v, got: %v", tt.shouldNotBeNil, result != nil)
			}
		})
	}
}

// TestPrefixTransformersFromStorageErrorHandling tests error handling in TransformFromStorage
func TestPrefixTransformersFromStorageErrorHandling(t *testing.T) {
	tests := []struct {
		name            string
		prefixes        []PrefixTransformer
		input           []byte
		defaultErr      error
		expectedErr     bool
		expectedStale   bool
	}{
		{
			name: "no matching prefix returns error",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("known:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result")}},
			},
			input:         []byte("unknown:data"),
			defaultErr:    fmt.Errorf("no match"),
			expectedErr:   true,
			expectedStale: false,
		},
		{
			name: "transformer error propagates",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("decrypt failed")}},
			},
			input:         []byte("enc:data"),
			defaultErr:    fmt.Errorf("default error"),
			expectedErr:   true,
			expectedStale: false,
		},
		{
			name: "identity transformer error allows fallback",
			prefixes: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("identity failed")}},
				{Prefix: []byte("enc:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result")}},
			},
			input:         []byte("enc:data"),
			defaultErr:    fmt.Errorf("default error"),
			expectedErr:   false,
			expectedStale: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(tt.defaultErr, tt.prefixes...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			_, stale, err := p.TransformFromStorage(ctx, tt.input, nil)

			if (err != nil) != tt.expectedErr {
				t.Errorf("expected error: %v, got: %v", tt.expectedErr, err != nil)
			}

			if stale != tt.expectedStale {
				t.Errorf("expected stale: %v, got: %v", tt.expectedStale, stale)
			}
		})
	}
}

// TestPrefixTransformersToStorageErrorHandling tests error handling in TransformToStorage
func TestPrefixTransformersToStorageErrorHandling(t *testing.T) {
	tests := []struct {
		name             string
		prefix           PrefixTransformer
		input            []byte
		shouldErr        bool
		expectedPrefix   []byte
	}{
		{
			name: "successful transformation includes prefix",
			prefix: PrefixTransformer{
				Prefix: []byte("enc:"),
				Transformer: &mockTransformer{
					transformToStorageResult: []byte("encrypted"),
				},
			},
			input:          []byte("plaintext"),
			shouldErr:      false,
			expectedPrefix: []byte("enc:"),
		},
		{
			name: "transformer error propagates",
			prefix: PrefixTransformer{
				Prefix: []byte("enc:"),
				Transformer: &mockTransformer{
					transformToStorageErr: fmt.Errorf("encrypt failed"),
				},
			},
			input:     []byte("plaintext"),
			shouldErr: true,
		},
		{
			name: "empty prefix is included",
			prefix: PrefixTransformer{
				Prefix: []byte{},
				Transformer: &mockTransformer{
					transformToStorageResult: []byte("data"),
				},
			},
			input:          []byte("plaintext"),
			shouldErr:      false,
			expectedPrefix: []byte{},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(fmt.Errorf("default"), tt.prefix)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			result, err := p.TransformToStorage(ctx, tt.input, nil)

			if (err != nil) != tt.shouldErr {
				t.Errorf("expected error: %v, got: %v", tt.shouldErr, err != nil)
			}

			if !tt.shouldErr && !bytes.HasPrefix(result, tt.expectedPrefix) {
				t.Errorf("expected result to have prefix %v, got: %v", tt.expectedPrefix, result)
			}
		})
	}
}

// TestPrefixTransformersMultiplePrefixes tests fallback behavior with multiple transformers
func TestPrefixTransformersMultiplePrefixes(t *testing.T) {
	tests := []struct {
