// mockTransformer implements the Transformer interface for testing
type mockTransformer struct {
	transformFromStorageResult []byte
	transformFromStorageStale  bool
	transformFromStorageErr    error
	transformToStorageResult   []byte
	transformToStorageErr      error
	fromStorageCalls           int
	toStorageCalls             int
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	m.fromStorageCalls++
	return m.transformFromStorageResult, m.transformFromStorageStale, m.transformFromStorageErr
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	m.toStorageCalls++
	return m.transformToStorageResult, m.transformToStorageErr
}

// roundTripTransformer implements a simple encrypt/decrypt round trip
type roundTripTransformer struct {
	prefix []byte
}

func (r *roundTripTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	// Simple transformation: remove the marker byte
	if len(data) == 0 {
		return nil, false, fmt.Errorf("empty data")
	}
	if data[0] != 'E' {
		return nil, false, fmt.Errorf("invalid encryption marker")
	}
	return data[1:], false, nil
}

func (r *roundTripTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	// Simple transformation: add a marker byte
	result := make([]byte, len(data)+1)
	result[0] = 'E'
	copy(result[1:], data)
	return result, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext returns its bytes as authenticated data
func TestDefaultContextAuthenticatedData(t *testing.T) {
