// TestPrefixTransformersFromStorageErrorHandling tests error handling in TransformFromStorage
func TestPrefixTransformersFromStorageErrorHandling(t *testing.T) {
	tests := []struct {
		name            string
		prefixes        []PrefixTransformer
		input           []byte
		defaultErr      error
		expectedErr     bool
		expectedStale   bool
	}{
		{
			name: "no matching prefix returns error",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("known:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result")}},
			},
			input:         []byte("unknown:data"),
			defaultErr:    fmt.Errorf("no match"),
			expectedErr:   true,
			expectedStale: false,
		},
		{
			name: "transformer error propagates",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("decrypt failed")}},
			},
			input:         []byte("enc:data"),
			defaultErr:    fmt.Errorf("default error"),
			expectedErr:   true,
			expectedStale: false,
		},
		{
			name: "identity transformer error allows fallback",
			prefixes: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("identity failed")}},
				{Prefix: []byte("enc:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result")}},
			},
			input:         []byte("enc:data"),
			defaultErr:    fmt.Errorf("default error"),
			expectedErr:   false,
			expectedStale: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(tt.defaultErr, tt.prefixes...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			_, stale, err := p.TransformFromStorage(ctx, tt.input, nil)

			if (err != nil) != tt.expectedErr {
				t.Errorf("expected error: %v, got: %v", tt.expectedErr, err != nil)
			}

			if stale != tt.expectedStale {
				t.Errorf("expected stale: %v, got: %v", tt.expectedStale, stale)
			}
		})
	}
}

// TestPrefixTransformersToStorageErrorHandling tests error handling in TransformToStorage
func TestPrefixTransformersToStorageErrorHandling(t *testing.T) {
	tests := []struct {
		name             string
		prefix           PrefixTransformer
		input            []byte
		shouldErr        bool
		expectedPrefix   []byte
	}{
		{
			name: "successful transformation includes prefix",
			prefix: PrefixTransformer{
				Prefix: []byte("enc:"),
				Transformer: &mockTransformer{
					transformToStorageResult: []byte("encrypted"),
				},
			},
			input:          []byte("plaintext"),
			shouldErr:      false,
			expectedPrefix: []byte("enc:"),
		},
		{
			name: "transformer error propagates",
			prefix: PrefixTransformer{
				Prefix: []byte("enc:"),
				Transformer: &mockTransformer{
					transformToStorageErr: fmt.Errorf("encrypt failed"),
				},
			},
			input:     []byte("plaintext"),
			shouldErr: true,
		},
		{
			name: "empty prefix is included",
			prefix: PrefixTransformer{
				Prefix: []byte{},
				Transformer: &mockTransformer{
					transformToStorageResult: []byte("data"),
				},
			},
			input:          []byte("plaintext"),
			shouldErr:      false,
			expectedPrefix: []byte{},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(fmt.Errorf("default"), tt.prefix)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			result, err := p.TransformToStorage(ctx, tt.input, nil)

			if (err != nil) != tt.shouldErr {
				t.Errorf("expected error: %v, got: %v", tt.shouldErr, err != nil)
			}

			if !tt.shouldErr && !bytes.HasPrefix(result, tt.expectedPrefix) {
				t.Errorf("expected result to have prefix %v, got: %v", tt.expectedPrefix, result)
			}
		})
	}
}

// TestPrefixTransformersMultiplePrefixes tests fallback behavior with multiple transformers
func TestPrefixTransformersMultiplePrefixes(t *testing.T) {
	tests := []struct {
		name            string
