			expectedErr:   false,
		},
		{
			name: "second prefix matches",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("error")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result2")}},
			},
			input:         []byte("first:data"),
			expectedIndex: 0,
			expectedErr:   true,
		},
		{
			name: "third prefix matches when first fails",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("error")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("error")}},
				{Prefix: []byte("third:"), Transformer: &mockTransformer{transformFromStorageResult: []byte("result3")}},
			},
			input:         []byte("third:data"),
			expectedIndex: 2,
			expectedErr:   false,
		},
	}

	for _, tt := range tests {
