}

// TestPrefixTransformersStaleFlagBehavior tests stale flag marking
func TestPrefixTransformersStaleFlagBehavior(t *testing.T) {
	tests := []struct {
		name              string
		prefixes          []PrefixTransformer
		input             []byte
		expectedStale     bool
		description       string
	}{
		{
			name: "first transformer not marked stale",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("primary:"), Transformer: &mockTransformer{
					transformFromStorageResult: []byte("data"),
					transformFromStorageStale:  false,
				}},
			},
			input:         []byte("primary:data"),
			expectedStale: false,
			description:   "primary transformer",
		},
		{
			name: "second transformer marked stale",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("primary:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("error")}},
				{Prefix: []byte("fallback:"), Transformer: &mockTransformer{
					transformFromStorageResult: []byte("data"),
					transformFromStorageStale:  false,
				}},
			},
			input:         []byte("fallback:data"),
			expectedStale: true,
			description:   "non-primary transformer",
		},
		{
			name: "stale flag from transformer plus non-first index",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("primary:"), Transformer: &mockTransformer{transformFromStorageErr: fmt.Errorf("error")}},
				{Prefix: []byte("secondary:"), Transformer: &mockTransformer{
					transformFromStorageResult: []byte("data"),
					transformFromStorageStale:  true,
				}},
			},
			input:         []byte("secondary:data"),
			expectedStale: true,
			description:   "stale flag from transformer OR non-first index",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := NewPrefixTransformers(fmt.Errorf("default"), tt.prefixes...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			_, stale, err := p.TransformFromStorage(ctx, tt.input, nil)

			// For some tests we expect errors, so we should check them
			if tt.description == "non-primary transformer" && err != nil {
				// Expected error from first transformer
			}

			if !tt.expectedErr && err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStale {
				t.Errorf("expected stale: %v, got: %v", tt.expectedStale, stale)
			}
		})
	}
}

// TestPrefixTransformersFirstTransformerUsedForWrite tests that first transformer is used for writes
func TestPrefixTransformersFirstTransformerUsedForWrite(t *testing.T) {
	first := &mockTransformer{transformToStorageResult: []byte("encrypted-v2")}
	second := &mockTransformer{transformToStorageResult: []byte("encrypted-v1")}

	transformers := []PrefixTransformer{
		{Prefix: []byte("v2:"), Transformer: first},
		{Prefix: []byte("v1:"), Transformer: second},
	}

	p := NewPrefixTransformers(fmt.Errorf("error"), transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	result, err := p.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Should use first transformer
	if first.toStorageCalls != 1 {
		t.Errorf("expected first transformer to be called once, got %d calls", first.toStorageCalls)
	}

	if second.toStorageCalls != 0 {
		t.Errorf("expected second transformer to not be called, got %d calls", second.toStorageCalls)
	}

	// Should have first transformer's prefix
	if !bytes.HasPrefix(result, []byte("v2:")) {
		t.Errorf("expected result to have first transformer's prefix, got: %v", result)
	}
}

