// TestPrefixTransformersDataContext tests that DataContext is passed to transformers
func TestPrefixTransformersDataContext(t *testing.T) {
	authData := []byte("authenticated-data")
	dataCtx := DefaultContext(authData)

	mock := &mockTransformer{
		transformToStorageResult: []byte("encrypted"),
		transformFromStorageResult: []byte("decrypted"),
	}

	transformer := PrefixTransformer{
		Prefix:      []byte("enc:"),
		Transformer: mock,
	}

	p := NewPrefixTransformers(fmt.Errorf("error"), transformer)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	// Transform to storage with context
	_, err := p.TransformToStorage(ctx, []byte("data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Transform from storage with context
	_, _, err = p.TransformFromStorage(ctx, []byte("enc:encrypted"), dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if mock.toStorageCalls != 1 {
		t.Errorf("expected to storage call, got %d", mock.toStorageCalls)
	}

	if mock.fromStorageCalls != 1 {
		t.Errorf("expected from storage call, got %d", mock.fromStorageCalls)
	}
}

