// TestPrefixTransformersFirstTransformerUsedForWrite tests that first transformer is used for writes
func TestPrefixTransformersFirstTransformerUsedForWrite(t *testing.T) {
	first := &mockTransformer{transformToStorageResult: []byte("encrypted-v2")}
	second := &mockTransformer{transformToStorageResult: []byte("encrypted-v1")}

	transformers := []PrefixTransformer{
		{Prefix: []byte("v2:"), Transformer: first},
		{Prefix: []byte("v1:"), Transformer: second},
	}

	p := NewPrefixTransformers(fmt.Errorf("error"), transformers...)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	result, err := p.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Should use first transformer
	if first.toStorageCalls != 1 {
		t.Errorf("expected first transformer to be called once, got %d calls", first.toStorageCalls)
	}

	if second.toStorageCalls != 0 {
		t.Errorf("expected second transformer to not be called, got %d calls", second.toStorageCalls)
	}

	// Should have first transformer's prefix
	if !bytes.HasPrefix(result, []byte("v2:")) {
		t.Errorf("expected result to have first transformer's prefix, got: %v", result)
	}
}

