// TestEmptyDataTransformation tests transformation of empty data
func TestEmptyDataTransformation(t *testing.T) {
	mock := &mockTransformer{
		transformToStorageResult: []byte(""),
		transformFromStorageResult: []byte(""),
	}

	transformer := PrefixTransformer{
		Prefix:      []byte("enc:"),
		Transformer: mock,
	}

	p := NewPrefixTransformers(fmt.Errorf("error"), transformer)
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	// Transform empty data to storage
	result, err := p.TransformToStorage(ctx, []byte{}, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if !bytes.Equal(result, []byte("enc:")) {
		t.Errorf("expected prefix only, got: %v", result)
	}

	// Transform from storage
	data, stale, err := p.TransformFromStorage(ctx, []byte("enc:"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if !bytes.Equal(data, []byte("")) {
		t.Errorf("expected empty result, got: %v", data)
	}

	if stale {
		t.Errorf("expected stale=false, got stale=true")
	}
}

